import os
import logging

logger = logging.getLogger(__name__)

class FilePathContext:
    def __init__(self, path):
        self.filepath = path if isinstance(path, str) else path.filepath
    def open(self, mode):
        return open(self.filepath, mode)

def resolve_format(fmt, filepath):
    _, ext = os.path.splitext(filepath.lower())
    if ext in ['.tsv', '.txt']:
        return 'tsv'
    if ext in ['.yaml', '.yml']:
        return 'yaml'
    return None

def strip_bom(line):
    if line.startswith('\ufeff'):
        return line[1:]
    return line

def parse_exchange_table_file(f):
    header = f.readline()
    header = strip_bom(header)
    for line in f:
        stripped = line.strip()
        if not stripped or stripped.startswith('#'):
            continue
        parts = stripped.split('\t')
        if len(parts) != 3:
            continue
        compound = parts[0].strip()
        if not compound:
            logging.warning('Empty compound name found in TSV line; skipping')
            continue
        lower = float(parts[1])
        upper = float(parts[2])
        if lower > upper:
            logging.warning('Invalid flux bounds for %s: lower %f > upper %f; skipping', compound, lower, upper)
            continue
        yield {'compound': compound, 'lower': lower, 'upper': upper}

def parse_exchange_yaml_file(context, f, default_compartment):
    for line in f:
        stripped = line.strip()
        if not stripped or stripped.startswith('#'):
            continue
        parts = stripped.split(':')
        if len(parts) < 3:
            continue
        compound = parts[0].strip()
        if not compound:
            logging.warning('Empty compound name found in YAML line; skipping')
            continue
        lower = float(parts[1])
        upper = float(parts[2])
        if lower > upper:
            logging.warning('Invalid flux bounds for %s: lower %f > upper %f; skipping', compound, lower, upper)
            continue
        compartment = parts[3].strip() if len(parts) > 3 else default_compartment
        yield {'compound': compound, 'lower': lower, 'upper': upper, 'compartment': compartment}

def detect_format_by_content(filepath):
    with open(filepath, 'r') as f:
        first_line = f.readline().strip()
    first_line = strip_bom(first_line)
    if not first_line:
        return None
    if '\t' in first_line:
        return 'tsv'
    if ':' in first_line:
        return 'yaml'
    return None

class ParseError(Exception):
    pass

def parse_exchange_file(path, default_compartment):
    # If file is empty, return empty iterator without error.
    try:
        with open(path, 'r') as f:
            first_line = f.read(1)
        if not first_line:
            return
    except FileNotFoundError:
        return  # treat missing file as empty
    context = FilePathContext(path)
    fmt = resolve_format(None, context.filepath)
    if fmt is None:
        fmt = detect_format_by_content(context.filepath)
    if fmt is None:
        raise ParseError('Unable to detect format of exchange file {}'.format(context.filepath))
    if fmt == 'tsv':
        logger.debug('Parsing exchange file {} as TSV'.format(context.filepath))
        with context.open('r') as f:
            yield from parse_exchange_table_file(f)
    elif fmt == 'yaml':
        logger.debug('Parsing exchange file {} as YAML'.format(context.filepath))
        with context.open('r') as f:
            yield from parse_exchange_yaml_file(context, f, default_compartment)
    else:
        raise ParseError('Unable to detect format of exchange file {}'.format(context.filepath))

