import os

def _system_call(command):
    stdout = f"Executed command: {command}"
    stderr = ""
    return {"stdout": stdout, "stderr": stderr, "returncode": 0}

def deblur_system_call(params, input_fp):
    logger = logging.getLogger(__name__)
    logger.debug("deblur system call params %s, input_fp %s", params, input_fp)

    # Type check: params must be iterable (not None)
    if params is None:
        raise TypeError()
    try:
        iter(params)
    except TypeError:
        raise TypeError()

    # File existence and extension validation
    if not os.path.exists(input_fp):
        raise FileNotFoundError()
    if not (input_fp.lower().endswith('.fasta') or input_fp.lower().endswith('.fa')):
        raise ValueError()

    # Flag conflict detection
    protected_flags = {'--seqs-fp', '--is-worker-thread', '--keep-tmp-files'}
    for item in params:
        if item in protected_flags:
            raise ValueError()

    script_name = 'deblur'
    script_subprogram = 'workflow'
    command = [script_name, script_subprogram, '--seqs-fp', input_fp, '--is-worker-thread', '--keep-tmp-files']
    command.extend(params)
    logger.debug("running command %s", command)
    return _system_call(command)

def main():
    logging.basicConfig(level=logging.DEBUG)
    input_fp = 'test_sequences.fasta'
    with open(input_fp, 'w') as f:
        f.write(">seq1\nACTG\n>seq2\nTGCA\n")
    params = ['--min-size', '50']
    result = deblur_system_call(params, input_fp)
    print('STDOUT:', result['stdout'])
    print('STDERR:', result['stderr'])
    print('Return code:', result['returncode'])

if __name__ == '__main__':
    main()

