    """ extract the umi and cell barcode from the read id (input as a
    string) using the specified separator """
    try:
        return read_id.split(sep)[-1].encode('utf-8'), read_id.split(sep)[-2].encode('utf-8')
    except IndexError:
        raise ValueError(
