gold_solution:
def get_cell_umi_read_string(read_id, sep='_', return_type='bytes'):
    parts = read_id.split(sep)
    if len(parts) < 3:
        raise ValueError(f"Read ID does not contain at least two separators: {read_id}")
    umi_str = parts[-1]
    cb_str = parts[-2]
    if not umi_str or not cb_str:
        raise ValueError(f"Empty field in last two fields of read ID: {read_id}")
    if return_type == 'bytes':
        return (umi_str.encode('utf-8'), cb_str.encode('utf-8'))
    elif return_type == 'str':
        return (umi_str, cb_str)
    else:
        raise ValueError("return_type must be 'bytes' or 'str'")

