import csv

def parse_reaction_file(path, default_compartment=None):
    """Parse reaction file (TSV or YAML) and yield reaction dicts with 'id', 'equation' (and optionally 'compartment')."""
    if path.endswith('.tsv'):
        with open(path, 'r') as f:
            reader = csv.DictReader(f, delimiter='\t')
            for row in reader:
                reaction = {'id': row['reaction_id'], 'equation': row['equation']}
                if default_compartment is not None:
                    reaction['compartment'] = default_compartment
                yield reaction
    elif path.endswith('.yaml'):
        with open(path, 'r') as f:
            lines = f.readlines()
        current = {}
        for line in lines:
            # Remove inline comments (assumes no '#' in values)
            comment = line.find('#')
            if comment >= 0:
                line = line[:comment]
            stripped = line.strip()
            if not stripped:
                continue
            if stripped.startswith('- '):
                if current:
                    yield current
                current = {}
                processed = stripped[2:]
                if ': ' in processed:
                    key, value = processed.split(': ', 1)
                    key = key.strip()
                    if key in ('id', 'equation'):
                        current[key] = value
            else:
                # Indented continuation line
                idx = line.find(':')
                if idx >= 0:
                    key = line[:idx].strip()
                    value = line[idx+1:].rstrip('\n')
                    # Remove exactly one leading space if it exists and is not followed by another space
                    if value.startswith(' ') and not (len(value) > 1 and value[1] == ' '):
                        value = value[1:]
                    if key in ('id', 'equation'):
                        current[key] = value
        if current:
            yield current
    else:
        raise ValueError(f"Unsupported file format: {path}")

def write_sample_files():
    """Create sample TSV and YAML reaction files with extra columns/fields and adversarial formatting."""
    # TSV with extra column (reversible), duplicate IDs, and whitespace in equation
    tsv_content = "reaction_id\tequation\treversible\nr1\tA -> B\ttrue\nr2\t B -> C \tfalse\nr1\tX -> Y\tfalse\n"
    with open('sample_reactions.tsv', 'w') as f:
        f.write(tsv_content)

    # YAML with comment, extra field (reversible), and whitespace in equation
    yaml_content = "# This is a comment\n- id: r3\n  equation: C -> D\n  reversible: true\n- id: r4\n  equation:   D -> E\n  reversible: false\n"
    with open('sample_reactions.yaml', 'w') as f:
        f.write(yaml_content)

# Prepare sample files
write_sample_files()

# Parse reaction files
parsed_tsv = list(parse_reaction_file('sample_reactions.tsv'))
parsed_yaml = list(parse_reaction_file('sample_reactions.yaml'))

# Print and set result as expected by the test
print("Parsed TSV reactions:")
for rxn in parsed_tsv:
    print(rxn)
print("Parsed YAML reactions:")
for rxn in parsed_yaml:
    print(rxn)
result = {'parsed_tsv': parsed_tsv, 'parsed_yaml': parsed_yaml}

