import os
import sys
from types import ModuleType

def parse_reaction_file(path, default_compartment=None):
    """Yield dicts with keys 'id', 'equation', optionally 'compartment'.

    Handles TSV and YAML formats. Detects duplicate IDs and prints warnings.
    Raises ValueError on malformed lines or unsupported format.
    """
    seen_ids = set()
    if path.endswith('.tsv'):
        with open(path, 'r') as f:
            lines = f.readlines()
        if not lines:
            raise ValueError(f"Empty file: {path}")
        header_line = None
        for line in lines:
            if line.strip():
                header_line = line
                break
        if header_line is None:
            raise ValueError(f"Empty file: {path}")
        col_names = header_line.strip().split()
        id_col = None
        eq_col = None
        comp_col = None
        for i, name in enumerate(col_names):
            lower = name.lower().strip()
            if lower in ('reaction_id', 'id'):
                id_col = i
            elif lower == 'equation':
                eq_col = i
            elif lower == 'compartment':
                comp_col = i
        if id_col is None or eq_col is None:
            raise ValueError(
                f"Missing required columns in TSV: need 'reaction_id'/'id' and 'equation'. Got headers: {col_names}"
            )
        num_cols = len(col_names)
        for line in lines[1:]:
            line = line.strip()
            if not line:
                continue
            tokens = line.split()
            if len(tokens) < num_cols:
                raise ValueError(f"Malformed row in TSV: insufficient columns in {path}")
            # Reconstruct fields accounting for multi-word equation
            ptr = 0
            fields = [None] * num_cols
            for i in range(num_cols):
                if i == eq_col:
                    # Equation consumes remaining tokens minus single-token columns after it
                    remaining_other = num_cols - 1 - i
                    if ptr + remaining_other > len(tokens):
                        raise ValueError(f"Malformed row in TSV: insufficient tokens for equation in {path}")
                    eq_token_count = len(tokens) - ptr - remaining_other
                    if eq_token_count < 1:
                        raise ValueError(f"Malformed row in TSV: equation field empty in {path}")
                    fields[i] = ' '.join(tokens[ptr:ptr+eq_token_count])
                    ptr += eq_token_count
                else:
                    fields[i] = tokens[ptr]
                    ptr += 1
            if ptr != len(tokens):
                raise ValueError(f"Malformed row in TSV: extra tokens in {path}")
            rid = fields[id_col].strip()
            eq = fields[eq_col].strip()
            comp = None
            if comp_col is not None:
                comp = fields[comp_col].strip()
            if not rid or not eq:
                raise ValueError(f"Malformed row in TSV: missing id or equation in {path}")
            if default_compartment is not None and comp is None:
                comp = default_compartment
            if rid in seen_ids:
                print(f"Warning: duplicate reaction ID '{rid}' in {path}")
            seen_ids.add(rid)
            reaction = {'id': rid, 'equation': eq}
            if comp is not None:
                reaction['compartment'] = comp
            yield reaction
    elif path.endswith('.yaml'):
        with open(path, 'r') as f:
            lines = f.readlines()
        blocks = []
        current_block = None
        for line in lines:
            stripped = line.strip()
            if not stripped:
                continue
            if stripped.startswith('- '):
                if current_block is not None:
                    blocks.append(current_block)
                current_block = [line]
            else:
                if current_block is not None and (line[0] in ' \t'):
                    current_block.append(line)
        if current_block is not None:
            blocks.append(current_block)
        for block in blocks:
            id_val = None
            eq_val = None
            comp_val = None
            for bline in block:
                stripped = bline.strip()
                if ':' in stripped:
                    key, value = stripped.split(':', 1)
                    key = key.strip()
                    value = value.strip()
                    if key == 'id':
                        id_val = value
                    elif key == 'equation':
                        eq_val = value
                    elif key == 'compartment':
                        comp_val = value
            if id_val is None or eq_val is None:
                raise ValueError(f"Malformed YAML block: missing id or equation in {path}")
            if default_compartment is not None and comp_val is None:
                comp_val = default_compartment
            if id_val in seen_ids:
                print(f"Warning: duplicate reaction ID '{id_val}' in {path}")
            seen_ids.add(id_val)
            reaction = {'id': id_val, 'equation': eq_val}
            if comp_val is not None:
                reaction['compartment'] = comp_val
            yield reaction
    else:
        raise ValueError(f"Unsupported file format: {path}")

# Create reaction_utils module for import
_reaction_utils = ModuleType('reaction_utils')
_reaction_utils.parse_reaction_file = parse_reaction_file
sys.modules['reaction_utils'] = _reaction_utils

